export const macroForSelection = (item: MenuItem, quantity: number): Macro => {
  if (item.control === "size" && item.sizeMacros?.length) {
    const size = item.sizeMacros.find(option => option.value === quantity) ?? item.sizeMacros.find(option => option.label === "Medium")!;
    return { calories: size.calories, protein: size.protein, carbs: size.carbs, fat: size.fat };
  }
  return {
    calories: item.calories * quantity,
    protein: item.protein * quantity,
    carbs: item.carbs * quantity,
    fat: item.fat * quantity,
  };
};

export const macroTotal = (items: { item: MenuItem; quantity: number; multiplier?: number }[]) =>
  items.reduce((sum, { item, quantity, multiplier = 1 }) => {
    const selected = macroForSelection(item, quantity);
    return {
      calories: sum.calories + selected.calories * multiplier,
      protein: sum.protein + selected.protein * multiplier,
      carbs: sum.carbs + selected.carbs * multiplier,
      fat: sum.fat + selected.fat * multiplier,
    };
  }, { calories: 0, protein: 0, carbs: 0, fat: 0 });
